sysevent_in_email_action.script:
// Copyrights belong to Discover Technologies LLC. © 2020 Discover Technologies LLC
// Script Continued Below
// 2.8 - 2022-03-09 - raj - STRY0114577 - Remove API Calls from Create My Task and Suggested Tasks
// DFCT0010647
var emailSysId = sys_email.getUniqueValue(); 
var grSys_Email = new GlideRecord('sys_email');
var a_count = new GlideAggregate('sys_attachment');
var grTask = new GlideRecordSecure('x_153465_discovert_route_task_instance');
var grSuggestedTask = new GlideRecordSecure('x_153465_discovert_suggested_taskers');
var defaultOU = '';
var grOM = new GlideRecordSecure('x_153465_discovert_discover_office_members');

var numAttachments = 0;

if(grSys_Email.get(emailSysId)){
	grTask.initialize();
	a_count.addQuery('table_sys_id', current.sys_id);
	a_count.addAggregate('COUNT');
	a_count.query();

	if (a_count.next()){
		numAttachments = a_count.getAggregate('COUNT');
	}

	grTask.short_description = email.subject;
	grTask.instructions = email.body_html;
	grTask.u_objective = email.body_html;

	grOM.addQuery('office_member', email.from_sys_id);
	grOM.addQuery('u_isdefaultou', true);
	grOM.query();
	while (grOM.next()) {
		defaultOU = grOM.getValue("u_default_ou");
	}
	if (defaultOU) {
		grTask.primary_assignee = defaultOU;
		grTask.primary_office = defaultOU;
		grTask.tasking_authority = defaultOU;
	}

	grTask.assigned_to = email.from_sys_id;
	grTask.work_notes = "This task was automatically created from an inbound email - \n Subject Line: " + email.subject;
	grTask = new CustomTaskerFieldHelper().mapFieldDataOnAction('EmailToTask', grTask, grTask);
	grTask.update();

	// STRY0114577
	grSuggestedTask.initialize();
	grSuggestedTask.u_created_task = grTask.sys_id;
	grSuggestedTask.tasker_created = true;
	grSuggestedTask.active = false;
	grSuggestedTask.u_original_email = emailSysId;
	grSuggestedTask.u_my_task_created = true;
	grSuggestedTask.insert();
}
